const items = $input.all();

// Handle both cases (data array OR direct rows)
let rows = [];

if (items[0].json.data) {
  rows = items[0].json.data;
} else {
  rows = items.map(item => item.json);
}

const today = new Date().toISOString().split('T')[0];

const toRemind = rows.filter(r => 
  r.date === today &&
  r.contextType === 'active' &&
  r.reminderSent !== true &&
  r.reminderSent !== 'true'
);

if (toRemind.length === 0) {
  return [{ json: { noTasks: true, message: 'No pending reminders for today' }}];
}

return toRemind.map(row => ({
  json: {
    slackUserId: row.slackUserId || '',
    userName: row.userName || '',
    originalText: row.originalText || '',   // ✅ Yeh line add ki
    taskDescription: row.taskDescription || '',
    date: row.date || ''
  }
}));

// Node: "Store Reminder Info"
// Position: After "Send Reminder DM"

const staticData = $getWorkflowStaticData('global');
if (!staticData.pendingReminders) staticData.pendingReminders = {};

const reminderData = $input.first().json;

// Google Sheets se row number lena hoga - iske liye pehle sheet query karni hogi
// Ya phir aap row number "Prepare Reminders" node mein pass kar sakte ho

const today = new Date().toISOString().split('T')[0];

if (!staticData.pendingReminders[today]) {
  staticData.pendingReminders[today] = [];
}

// Slack response se thread_ts nikalo (yeh critical hai!)
// Slack node ka output mein ts hota hai
const slackResponse = $input.first().json;
const threadTs = slackResponse.ts || '';

staticData.pendingReminders[today].push({
  userId: reminderData.userId,
  userName: reminderData.userName,
  taskDescription: reminderData.taskDescription,
  sheetRowIndex: reminderData.sheetRowIndex,
  reminderThreadTs: threadTs,  // ← Yeh reply match karne ke liye
  reminderSent: true,
  status: 'pending'
});

return [{ json: { stored: true, threadTs: threadTs } }];
